72	// runInit implements the CLI interface layer for the init command
73	func (f *CommandFactory) runInit(cmd *cobra.Command, args []string) error {
74		// --global mode: one-time machine setup, bypasses project checks.
75		if globalMode, _ := cmd.Flags().GetBool("global"); globalMode {
76			if err := initGlobal(); err != nil {
77				cmd.SilenceUsage = true
78				return err
79			}
80			if silent, _ := cmd.Flags().GetBool("silent"); !silent {
81				_, _ = fmt.Fprint(cmd.OutOrStdout(), "✅ DDx global machine setup complete.\n")
82			}
83			return nil
84		}
85	
86		// Extract flags from cobra.Command
87		initForce, _ := cmd.Flags().GetBool("force")
88		initNoGit, _ := cmd.Flags().GetBool("no-git")
89		initSilent, _ := cmd.Flags().GetBool("silent")
90		initSkipClaude, _ := cmd.Flags().GetBool("skip-claude-injection")
91		initRepository, _ := cmd.Flags().GetString("repository")
92		initBranch, _ := cmd.Flags().GetString("branch")
93	
94		// Create options struct for business logic
95		opts := InitOptions{
96			Force:               initForce,
97			NoGit:               initNoGit,
98			Silent:              initSilent,
99			SkipClaudeInjection: initSkipClaude,
100			Repository:          initRepository,
101			Branch:              initBranch,
102			DDxVersion:          f.Version,
103		}
104	
105		// Handle user output
106		if !opts.Silent {
107			_, _ = fmt.Fprint(cmd.OutOrStdout(), "🚀 Initializing DDx in current project...\n")
108			_, _ = fmt.Fprintln(cmd.OutOrStdout())
109		}
110	
111		// Call pure business logic function
112		_, err := initProject(f.WorkingDir, opts)
113		if err != nil {
114			cmd.SilenceUsage = true
115			return err
116		}
117	
118		// Handle user output based on results
119		if !opts.Silent {
120			_, _ = fmt.Fprint(cmd.OutOrStdout(), "✅ DDx initialized successfully!\n")
121			_, _ = fmt.Fprintln(cmd.OutOrStdout())
122			_, _ = fmt.Fprint(cmd.OutOrStdout(), "Next steps:\n")
123			_, _ = fmt.Fprint(cmd.OutOrStdout(), "  ddx install helix   - Install HELIX workflow (optional)\n")
124			_, _ = fmt.Fprint(cmd.OutOrStdout(), "  ddx doctor          - Check installation health\n")
125			_, _ = fmt.Fprintln(cmd.OutOrStdout())
126		}
127	
128		return nil
129	}
