131	// initProject is the pure business logic function for project initialization
132	func initProject(workingDir string, opts InitOptions) (*InitResult, error) {
133		result := &InitResult{}
134	
135		// Validate git repository unless --no-git flag is used
136		if !opts.NoGit {
137			if err := validateGitRepo(workingDir); err != nil {
138				return nil, NewExitError(1, err.Error())
139			}
140		}
141	
142		// Guard against running inside an execute-bead context.
143		if os.Getenv("DDX_EXECUTE_BEAD_ID") != "" {
144			return nil, NewExitError(1,
145				"ddx init cannot be run inside an execute-bead context (DDX_EXECUTE_BEAD_ID is set)")
146		}
147		// Guard against running inside an execute-bead worktree. These are isolated
148		// execution environments under .ddx/.execute-bead-wt-*; running ddx init
149		// inside one would overwrite the project's .ddx/ config and beads.jsonl.
150		if isExecuteBeadWorktree(workingDir) {
151			return nil, NewExitError(1,
152				"ddx init cannot be run inside an execute-bead worktree (.ddx/.execute-bead-wt-*)")
153		}
154	
155		// Guard against nested workspaces: if a parent directory already has a
156		// .ddx/ workspace, refuse to create a second one in a subdirectory.
157		// This prevents the split-tracker bug where commands from different
158		// directories operate on different .ddx/beads.jsonl files.
159		if parent := findParentDDxWorkspace(workingDir); parent != "" {
160			return nil, NewExitError(1, fmt.Sprintf(
161				".ddx/ workspace already exists at %s. "+
162					"DDx anchors to the git repository root; run commands from any directory.",
163				parent))
164		}
165	
166		// Check if config already exists
167		configPath := ddxroot.JoinProject(workingDir, "config.yaml")
168		if _, err := os.Stat(configPath); err == nil {
169			if !opts.Force {
170				// Config exists and --force not used - exit code 2 per contract
171				return nil, NewExitError(2, ".ddx/config.yaml already exists. Use --force to overwrite.")
172			}
173			// With --force flag, we proceed to overwrite without backup
174		}
175	
176		// Check if library path exists using working directory
177		cfg, err := config.LoadWithWorkingDir(workingDir)
178		libraryExists := true
179		if err != nil || cfg.Library == nil || cfg.Library.Path == "" {
180			libraryExists = false
181		} else if _, err := os.Stat(filepath.Join(workingDir, cfg.Library.Path)); os.IsNotExist(err) {
182			libraryExists = false
183		}
184		result.LibraryExists = libraryExists
185	
186		// Create configuration with defaults
187		localConfig := createProjectConfig()
188	
189		// Apply default values (including repository settings)
190		localConfig.ApplyDefaults()
191	
192		// Add validation during creation
193		if err := validateConfiguration(localConfig); err != nil {
194			return nil, NewExitError(1, fmt.Sprintf("Configuration validation failed: %v", err))
195		}
196	
197		// Try to load existing config to preserve settings (even if library doesn't exist yet)
198		if cfg != nil && err == nil {
199			// Note: Version is NOT copied - always upgrade to current version via ApplyDefaults
200			// Copy library settings if they exist (unless overridden by flags)
201			if cfg.Library != nil && localConfig.Library != nil {
202				if cfg.Library.Path != "" {
203					localConfig.Library.Path = cfg.Library.Path
204				}
205				if cfg.Library.Repository != nil && localConfig.Library.Repository != nil {
206					// Only copy existing values if not overridden by flags
207					if opts.Repository == "" && cfg.Library.Repository.URL != "" {
208						localConfig.Library.Repository.URL = cfg.Library.Repository.URL
209					}
210					if opts.Branch == "" && cfg.Library.Repository.Branch != "" {
211						localConfig.Library.Repository.Branch = cfg.Library.Repository.Branch
212					}
213				}
214			}
215		}
216	
217		// Apply flag overrides AFTER loading existing config (flags have highest priority)
218		if opts.Repository != "" {
219			if localConfig.Library == nil {
220				localConfig.Library = &config.LibraryConfig{}
221			}
222			if localConfig.Library.Repository == nil {
223				localConfig.Library.Repository = &config.RepositoryConfig{}
224			}
225			localConfig.Library.Repository.URL = opts.Repository
226		}
227		if opts.Branch != "" {
228			if localConfig.Library == nil {
229				localConfig.Library = &config.LibraryConfig{}
230			}
231			if localConfig.Library.Repository == nil {
232				localConfig.Library.Repository = &config.RepositoryConfig{}
233			}
234			localConfig.Library.Repository.Branch = opts.Branch
235		}
236	
237		// Create .ddx directory first
238		localDDxPath := ddxroot.JoinProject(workingDir)
239		if err := os.MkdirAll(localDDxPath, 0755); err != nil {
240			return nil, NewExitError(1, fmt.Sprintf("Failed to create .ddx directory: %v", err))
241		}
242	
243		// Save local configuration using ConfigLoader
244		loader, err := config.NewConfigLoaderWithWorkingDir(workingDir)
245		if err != nil {
246			return nil, NewExitError(1, fmt.Sprintf("Failed to create config loader: %v", err))
247		}
248		if err := loader.SaveConfig(localConfig, ".ddx/config.yaml"); err != nil {
249			return nil, NewExitError(1, fmt.Sprintf("Failed to save configuration: %v", err))
250		}
251		result.ConfigCreated = true
252	
253		if err := ensureProjectGitignoreRules(workingDir, initGitignoreRules); err != nil {
254			return nil, NewExitError(1, fmt.Sprintf("Failed to update .gitignore: %v", err))
255		}
256		if !opts.NoGit {
257			if err := untrackLegacyRunStateFiles(context.Background(), workingDir); err != nil {
258				return nil, NewExitError(1, fmt.Sprintf("Failed to migrate legacy run-state tracking: %v", err))
259			}
260		}
261	
262		// Write .ddx/versions.yaml (system-managed, tracks binary version)
263		writeProjectVersions(workingDir, opts.DDxVersion)
264	
265		if !opts.NoGit {
266			// Inject initial meta-prompt if the prompt file actually exists (unless explicitly skipped)
267			if !opts.SkipClaudeInjection {
268				if err := injectInitialMetaPrompt(localConfig, workingDir); err != nil {
269					// Don't fail - meta-prompt is optional enhancement
270					// Only warn if the specific prompt file exists but has issues
271					promptPath := localConfig.GetMetaPrompt()
272					if promptPath != "" {
273						fullPromptPath := filepath.Join(workingDir, localConfig.Library.Path, promptPath)
274						if _, statErr := os.Stat(fullPromptPath); statErr == nil {
275							_, _ = fmt.Fprintf(os.Stderr, "Warning: Failed to inject meta-prompt: %v\n", err)
276						}
277					}
278				}
279			}
280	
281			// Generate AGENTS.md with guidance for AI agents working in this repo.
282			generateAgentsMD(workingDir)
283	
284			// Commit config and versions files
285			ctx := context.Background()
286			gitAdd := gitpkg.Command(ctx, workingDir, "add", ".ddx/config.yaml", ".ddx/versions.yaml", "AGENTS.md", ".gitignore")
287			if err := gitAdd.Run(); err != nil {
288				return nil, NewExitError(1, fmt.Sprintf("Failed to stage config file: %v", err))
289			}
290	
291			gitCommit := gitpkg.Command(ctx, workingDir, "commit", "-m", "chore: add DDx configuration")
292			if err := gitCommit.Run(); err != nil {
293				return nil, NewExitError(1, fmt.Sprintf("Failed to commit config file: %v", err))
294			}
295	
296			// Enable per-worktree git config so that `git config --local` inside
297			// linked worktrees (e.g. execute-bead worktrees) writes to a
298			// worktree-specific file rather than the shared .git/config. This
299			// prevents agents from accidentally corrupting repo-level settings like
300			// core.bare when running in an isolated worktree.
301			gitWorktreeCfg := gitpkg.Command(ctx, workingDir, "config", "extensions.worktreeConfig", "true")
302			_ = gitWorktreeCfg.Run() // best-effort; older git versions may not support it
303		}
304	
305		// Store config for CLI layer to use for sync setup
306		result.Config = localConfig
307	
308		// Configuration already saved above
309	
310		return result, nil
311	}
