370	// writeProjectVersions writes .ddx/versions.yaml with the current binary version.
371	// This file is system-managed and committed to git for version gating.
372	func writeProjectVersions(workingDir, ddxVersion string) {
373		if ddxVersion == "" || ddxVersion == "dev" {
374			ddxVersion = "dev"
375		}
376		versionsPath := ddxroot.JoinProject(workingDir, "versions.yaml")
377		content := fmt.Sprintf("ddx_version: %q\n", ddxVersion)
378		if err := os.WriteFile(versionsPath, []byte(content), 0644); err != nil {
379			_, _ = fmt.Fprintf(os.Stderr, "Warning: could not write .ddx/versions.yaml: %v\n", err)
380		}
